{
  "grammar": [
    {
      "pattern": "請 + Verb + Object",
      "structure": ["請", "Verb", "Object"],
      "explanation_en": "Use '請' to politely ask someone to do something. It is a common way to make requests in signs and notices.",
      "title": "Polite Requests with 請",
      "meaning": "Please do something",
      "when_to_use": ["When reading signs that ask people to take action", "When making polite requests in public places"],
      "when_not_to_use": ["When the request is urgent or mandatory (use 必須 instead)", "When talking to close friends (use 你 Verb 一下 instead)"],
      "pragmatic_notes": "In Taiwan, 請 is very common on signs and announcements. It softens the request and shows respect.",
      "word_order_notes": "請 always comes before the verb. The object follows the verb.",
      "english_contrast": "In English, 'please' can come at the beginning or end. In Chinese, 請 must be at the beginning of the request.",
      "korean_contrast": "In Korean, '주세요' is added after the verb. In Chinese, 請 is placed before the verb.",
      "negative_examples": [
        {
          "text": "你請進來。",
          "error": "請 should come before the verb, not after the subject."
        }
      ],
      "incorrect_examples": [
        {
          "text": "請你進來。",
          "error": "This is actually correct. The example is kept to show that 請 can be followed by a subject in some contexts, but in signs, 請 + Verb is more common."
        }
      ],
      "transformation_drills": ["Change '請進' to '請進來'", "Change '請坐' to '請坐下'"],
      "production_drills": ["Write a sign asking people to 'please wait'", "Write a sign asking people to 'please sign here'"],
      "common_error_patterns": ["Placing 請 after the verb", "Using 請 with negative commands"],
      "repair_feedback": {
        "word_order": "請 must come before the verb.",
        "politeness": "Using 請 makes the request polite.",
        "vocabulary": "Use 請 with common verbs like 進, 坐, 等."
      }
    },
    {
      "pattern": "Subject + 不可以 + Verb",
      "structure": ["Subject", "不可以", "Verb"],
      "explanation_en": "Use '不可以' to express prohibition or that something is not allowed. It is common in rules and signs.",
      "title": "Prohibition with 不可以",
      "meaning": "Cannot / must not do something",
      "when_to_use": ["When reading signs that forbid actions", "When explaining rules to others"],
      "when_not_to_use": ["When the prohibition is very formal (use 禁止 instead)", "When talking about ability (use 不會 instead)"],
      "pragmatic_notes": "In Taiwan, 不可以 is used in everyday speech and on signs. It is less formal than 禁止 but very common.",
      "word_order_notes": "不可以 comes before the verb. The subject is often omitted in signs.",
      "english_contrast": "In English, 'cannot' or 'must not' is used. In Chinese, 不可以 is placed before the verb.",
      "korean_contrast": "In Korean, '-(으)면 안 되다' is used. In Chinese, 不可以 is simpler and placed before the verb.",
      "negative_examples": [
        {
          "text": "不可以你進來。",
          "error": "不可以 should come before the verb, not after the subject."
        }
      ],
      "incorrect_examples": [
        {
          "text": "你不可進來。",
          "error": "The correct form is 不可以, not 不可."
        }
      ],
      "transformation_drills": ["Change '不可以吃' to '不可以喝'", "Change '不可以拍照' to '不可以錄影'"],
      "production_drills": ["Write a sign saying 'No smoking'", "Write a sign saying 'No parking'"],
      "common_error_patterns": ["Using 不可 instead of 不可以", "Placing 不可以 after the verb"],
      "repair_feedback": {
        "word_order": "不可以 must come before the verb.",
        "politeness": "不可以 is direct; for polite prohibition, use 請不要.",
        "vocabulary": "Use 不可以 with verbs like 吃, 喝, 拍照."
      }
    },
    {
      "pattern": "Notice: [Location] + [Action] + [Time/Date]",
      "structure": ["Location", "Action", "Time/Date"],
      "explanation_en": "This is a common structure for notices and announcements. It states where something will happen, what will happen, and when.",
      "title": "Notice Structure",
      "meaning": "Notice about an event or change",
      "when_to_use": ["When reading public notices", "When writing simple announcements"],
      "when_not_to_use": ["When the notice is very formal (use 公告 instead)", "When the notice is a warning (use 警告 instead)"],
      "pragmatic_notes": "In Taiwan, notices often start with the location, then the action, then the time. This structure is clear and direct.",
      "word_order_notes": "The order is usually: Location + Action + Time. Time can also come at the beginning for emphasis.",
      "english_contrast": "In English, time often comes first. In Chinese, location often comes first in notices.",
      "korean_contrast": "In Korean, time often comes first. In Chinese, location is often emphasized first.",
      "negative_examples": [
        {
          "text": "時間上午九點開放圖書館。",
          "error": "The location should come before the action. Correct: 圖書館上午九點開放。"
        }
      ],
      "incorrect_examples": [
        {
          "text": "開放圖書館上午九點。",
          "error": "The action should come after the location. Correct: 圖書館上午九點開放。"
        }
      ],
      "transformation_drills": ["Change '公園早上六點開放' to '公園早上七點開放'", "Change '商店晚上十點關閉' to '商店晚上十一點關閉'"],
      "production_drills": ["Write a notice: 'Library open 9am'", "Write a notice: 'Park closed 6pm'"],
      "common_error_patterns": ["Putting time before location", "Forgetting to include the action"],
      "repair_feedback": {
        "word_order": "Location usually comes first in notices.",
        "politeness": "Notices are direct; no need for polite markers.",
        "vocabulary": "Use location words like 圖書館, 公園, 商店."
      }
    }
  ]
}
